if not TDX.exists():
    raise SystemExit(f"missing CLI binary: {TDX}")

creds = sys.argv[1]
pass_count = skip_count = fail_count = 0
for endpoint, mode, min_tier, argv in CELLS:
    label = f"{endpoint}::{mode}"
    proc = subprocess.run(
        [str(TDX), "--creds", creds, *argv, "--format", "json"],
        cwd=REPO,
        stdout=subprocess.PIPE,
        stderr=subprocess.STDOUT,
        check=False,
    )
    output = (proc.stdout or b"").decode("utf-8", errors="replace")
    msg = output.lower()
    if proc.returncode == 0:
        print(f"  {label:60s} PASS")
        pass_count += 1
    elif "permission" in msg or "subscription" in msg:
        print(f"  {label:60s} SKIP: tier-permission (declared min_tier={min_tier})")
        skip_count += 1
    elif "no data found" in msg:
        print(f"  {label:60s} PASS  (no data)")
        pass_count += 1
    else:
        print(f"  {label:60s} FAIL  {output.strip()}")
        fail_count += 1

print(f"\nCLI: {pass_count} PASS, {skip_count} SKIP, {fail_count} FAIL")
print(f"COUNTS:{pass_count}:{skip_count}:{fail_count}")
sys.exit(1 if fail_count > 0 else 0)
